export type PostSection =
  | { type: "p"; text: string }
  | { type: "h2"; text: string }
  | { type: "h3"; text: string }
  | { type: "ul"; items: string[] }
  | { type: "quote"; text: string }
  /** A command/code block. `lang` (e.g. "bash", "php") shows in the header bar; `label` overrides it (e.g. "supervisor.conf"). */
  | { type: "code"; code: string; lang?: string; label?: string }
  /** An inline image within the article body. `src` is an absolute URL or /public path. */
  | { type: "image"; src: string; alt: string; caption?: string };

export type Post = {
  slug: string;
  title: string;
  /** Used as the meta description — keep under ~160 characters. */
  excerpt: string;
  category: string;
  tags: string[];
  keywords: string[];
  image: string;
  imageAlt: string;
  date: string; // ISO date
  readTime: string;
  content: PostSection[];
};

